$columns: 12
$gutter: 2% // Must be %


// Calculate the total sum of a list (context)
@function list-sum($list)
  // zero out the initial sum
  $sum: 0
  // loop through each value in the list adding it to $list-sum
  @for $i from 1 through length($list)
    $sum: $sum + nth($list, $i)
  @return $sum


// Find column count
@function column-count($columns)
  @if type-of($columns) == number
    @return $columns
  @if type-of($columns) == list
    @return length($columns)


// calculate the width of individual columns
@function list-column-width($location, $columns)
  // send a warning if this is used when $columns is not a list
  @if type-of($columns) != list
    @warn "The column-list-sum function requires the variable $columns to be a list."
  @else
    // divide the column from its context
    @return nth($columns, $location) / list-sum($columns)


// Calculate the width spanning multiple columns
@function column-span($span, $location: 1, $columns: $columns)

  // Equal width columns
  @if type-of($columns) == number
    @return $span * (100% / $columns)

  // Variable width columns
  @if type-of($columns) == list
    // zero out initial sum
    $sum: 0
    // from start point to end point
    @for $i from $location to ($location + $span)
      $sum: $sum + list-column-width($i, $columns)
    @return percentage($sum)


// Gutters to be removed from columns
@function gutter-offset($gutter, $columns)
  $gutter-sum: $gutter * (column-count($columns) - 1)


@function grid-span($span, $location: 1, $columns: $columns)

// TEST

$columns: 1, 2, 4, 8, 16, 32
@debug column-span(3, 3)

=structure-float($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter, $grouped-styles: false)
  @if $dir == ltr or $dir == both
    @if $location > 1 and $location < column-count($columns)
      @if $grouped-styles == false
        margin-right: -100%
        float: left
      margin-left: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      @if $grouped-styles == false
        margin-right: -100%
        float: left
      margin-left: 0
    @if $location == column-count($columns)
      float: right
      margin-right: 0
  @if $dir == rtl
    @if $location > 1 and $location < column-count($columns)
      @if $grouped-styles == false
        margin-left: -100%
        float: right
      margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
    @if $location == 1
      @if $grouped-styles == false
        margin-left: -100%
        float: right
      margin-right: 0
    @if $location == column-count($columns)
      float: left
      margin-left: 0
  @if $dir == both
    #{$rtl-selector} &
      @if $location > 1 and $location < column-count($columns)
        @if $grouped-styles == false
          margin-left: -100%
          float: right
        margin-right: grid-span($location - 1, 1, $columns, $gutter) + $gutter
      @if $location == 1
        @if $grouped-styles == false
          margin-left: -100%
          float: right
        margin-right: 0
      @if $location == column-count($columns)
        float: left
        margin-left: 0

@import compass/utilities/general/float
@import blueprint/buttons

//
  Use the following HTML code to place the buttons on your site:

  <button type="submit" class="button positive">
    <img src="css/blueprint/plugins/buttons/icons/tick.png" alt=""/> Save
  </button>

  <a class="button" href="/password/reset/">
    <img src="css/blueprint/plugins/buttons/icons/key.png" alt=""/> Change Password
  </a>

  <a href="#" class="button negative">
    <img src="css/blueprint/plugins/buttons/icons/cross.png" alt=""/> Cancel
  </a>

a.button
  // you can pass "left" or "right" to +anchor-button to float it in that direction
  // or you can pass no argument to leave it inline-block (cross browser safe!) within
  // the flow of your page.
  +anchor-button(left)
  // All the button color mixins take 4 optional arguments:
  // font color, background color, border color, border highlight color
  // the first three default to constants set in blueprint/buttons.sass
  // the last one defaults to a shade lighter than the border color.
  +button-colors
  +button-hover-colors
  +button-active-colors

button
  // The +button-button mixin is just like the +anchor-button mixin, but for <button> elements.
  +button-button(left)
  +button-colors
  +button-hover-colors
  +button-active-colors

// We can change the colors for buttons of certain classes, etc.
a.positive, button.positive
  color: #529214
  +button-hover-colors(#529214, #E6EFC2, #C6D880)
  +button-active-colors(#FFF, #529214, #529214)

a.negative, button.negative
  color: #D12F19
  +button-hover-colors(#D12F19, #FBE3E4, #FBC2C4)
  +button-active-colors(#FFF, #D12F19, #D12F19)

